-- ============================================\n-- 高铁小区健康检查索引优化脚本\n-- 用于提升查询性能\n-- ============================================\n\n-- 说明：\n-- 1. 本脚本创建优化索引以提升高铁小区健康检查性能\n-- 2. 使用 IF NOT EXISTS 避免重复创建\n-- 3. 索引已存在时会自动跳过\n-- 4. 建议在业务低峰期执行\n\n-- ============================================\n-- MySQL 索引优化（告警表）\n-- ============================================\n\n-- 切换到目标数据库\nUSE optimization_toolbox;\n\n-- 1. 为 cur_alarm 表添加索引\n-- 注意：文本字段需要指定前缀长度\n\n-- 为 alarm_code_name 添加索引\nCREATE INDEX IF NOT EXISTS idx_alarm_code_name \nON cur_alarm(alarm_code_name(100));\n\n-- 为 alarm_title 添加索引\nCREATE INDEX IF NOT EXISTS idx_alarm_title \nON cur_alarm(alarm_title(100));\n\n-- 为 alarm_reason 添加索引\nCREATE INDEX IF NOT EXISTS idx_alarm_reason \nON cur_alarm(alarm_reason(200));\n\n-- 为 occur_time 添加索引（用于时间排序）\nCREATE INDEX IF NOT EXISTS idx_alarm_occur_time \nON cur_alarm(occur_time DESC);\n\n-- ============================================\n-- PostgreSQL 索引优化（性能指标表）\n-- ============================================\n\n-- 注意：在PostgreSQL中执行以下语句\n-- 4G指标表复合索引：cgi + start_time\nCREATE INDEX IF NOT EXISTS idx_metrics_4g_cgi_time \nON cell_4g_metrics(cgi, start_time DESC);\n\n-- 5G指标表复合索引：Ncgi + start_time\nCREATE INDEX IF NOT EXISTS idx_metrics_5g_cgi_time \nON cell_5g_metrics("Ncgi", start_time DESC);\n\n-- 4G指标表单独的start_time索引\nCREATE INDEX IF NOT EXISTS idx_metrics_4g_time \nON cell_4g_metrics(start_time DESC);\n\n-- 5G指标表单独的start_time索引\nCREATE INDEX IF NOT EXISTS idx_metrics_5g_time \nON cell_5g_metrics(start_time DESC);\n\n-- 4G指标表单独的cgi索引\nCREATE INDEX IF NOT EXISTS idx_metrics_4g_cgi \nON cell_4g_metrics(cgi);\n\n-- 5G指标表单独的Ncgi索引\nCREATE INDEX IF NOT EXISTS idx_metrics_5g_cgi \nON cell_5g_metrics("Ncgi");\n\n-- ============================================\n-- 更新表统计信息\n-- ============================================\n\n-- MySQL 更新统计信息\nANALYZE TABLE cur_alarm;\n\n-- PostgreSQL 更新统计信息\n-- ANALYZE cell_4g_metrics;\n-- ANALYZE cell_5g_metrics;\n\n-- ============================================\n-- 查看索引创建结果\n-- ============================================\n\n-- MySQL 查看索引\nSHOW INDEX FROM cur_alarm;\n\n-- PostgreSQL 查看索引\n-- \d cell_4g_metrics\n-- \d cell_5g_metrics\n\n-- ============================================\n-- 执行完成提示\n-- ============================================\n\nSELECT '索引优化脚本执行完成！' as message;\n